const express = require('express');
const multer = require('multer');
const sharp = require('sharp');
const fs = require('fs');
const path = require('path');

const app = express();

const storage = multer.diskStorage({
    destination: function (req, file, cb) {
        cb(null, './public/uploads')
    },
    filename: function (req, file, cb) {
        cb(null, file.fieldname + '-' + Date.now() + path.extname(file.originalname));
    }
});

const upload = multer({
    storage: storage,
    fileFilter: function (req, file, cb) {
        const filetypes = /jpeg|jpg|png|gif|svg|pdf|doc|docx|zip/;
        const mimetype = filetypes.test(file.mimetype);
        const extname = filetypes.test(path.extname(file.originalname).toLowerCase());

        if (mimetype && extname) {
            return cb(null, true);
        }
        cb("Invalid file type. Only jpeg, jpg, png, gif, svg, pdf, doc, docx, zip files are allowed.");
    },
    limits: {
        fileSize: req.user.role === 'enterprise' ? Infinity : 1024 * 1024 * 5
    }
}).single('avatar');

app.post('/upload', (req, res) => {
    upload(req, res, (err) => {
        if (err) {
            res.status(500).json({ error: err });
        } else {
            const ext = path.extname(req.file.filename);
            if (ext === '.jpeg' || ext === '.jpg' || ext === '.png' || ext === '.gif' || ext === '.svg') {
                const thumbnailPath = './public/uploads/thumbnails/' + path.basename(req.file.filename, ext) + '-thumbnail' + ext;
                sharp(req.file.path)
                    .resize(200)
                    .toFile(thumbnailPath, (err, resizeImage) => {
                        if (err) {
                            res.status(500).json({ error: err });
                        } else {
                            res.status(200).json({ message: 'File uploaded successfully', file: req.file, thumbnail: thumbnailPath });
                        }
                    });
            } else {
                res.status(200).json({ message: 'File uploaded successfully', file: req.file });
            }
        }
    });
});

app.listen(3000, () => console.log('Server started on port 3000'));